import{_ as t,c as a,o as s,a5 as n}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse(`{"title":"FAQ & Troubleshooting","titleTemplate":"NpgsqlRest","description":"Frequently asked questions about NpgsqlRest: missing endpoints, 404s, parameter naming, authentication, login endpoints, uploads, SSE, CORS, deployment, testing, performance, logging, and troubleshooting.","frontmatter":{"outline":[2,3],"title":"FAQ & Troubleshooting","titleTemplate":"NpgsqlRest","description":"Frequently asked questions about NpgsqlRest: missing endpoints, 404s, parameter naming, authentication, login endpoints, uploads, SSE, CORS, deployment, testing, performance, logging, and troubleshooting.","head":[["meta",{"name":"keywords","content":"npgsqlrest faq, npgsqlrest troubleshooting, endpoint not found, postgresql rest api questions, npgsqlrest 404, sql injection, npgsqlrest testing, npgsqlrest cors, postgresql login endpoint, file upload postgresql, server-sent events postgresql"}],["meta",{"property":"og:title","content":"NpgsqlRest FAQ & Troubleshooting"}],["meta",{"property":"og:description","content":"Frequently asked questions about NpgsqlRest."}],["meta",{"property":"og:type","content":"article"}],["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/guide/faq.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/guide/faq.html"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"NpgsqlRest FAQ & Troubleshooting"}],["meta",{"name":"twitter:description","content":"Frequently asked questions about NpgsqlRest."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"FAQPage\\",\\"mainEntity\\":[{\\"@type\\":\\"Question\\",\\"name\\":\\"What is NpgsqlRest?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"NpgsqlRest is a self-contained executable that connects to PostgreSQL and automatically creates REST API endpoints from plain SQL script files, database functions, and procedures. No code generation step, no ORM — just SQL.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What PostgreSQL versions are supported?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"PostgreSQL 13 and newer. Discovery uses standard pgcatalog views that are stable across PostgreSQL versions.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What .NET version is required?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"None, for most users — the standalone executable and the Docker image are fully self-contained (AOT-compiled). The NuGet library targets .NET 10.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is it safe from SQL injection?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes, by construction. Client-supplied values are always sent as PostgreSQL protocol parameters — never concatenated into SQL text. The SQL that runs is the SQL you wrote in the file, function, or procedure; a request can only choose parameter values, never SQL fragments. There is no query-building l\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How does NpgsqlRest compare to PostgREST or Supabase?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"See the detailed comparison blog post for a full feature-by-feature breakdown. The short version: PostgREST turns your tables into an API you query from the client; NpgsqlRest turns your SQL (files, functions, procedures) into an API you design.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use it inside an existing ASP.NET Core application?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — the standalone executable is a wrapper around the NpgsqlRest NuGet middleware. In your own app: app.UseNpgsqlRest(new NpgsqlRestOptions(connectionString) { ... }). The plugins (SQL file source, TypeScript client, Dart client, OpenAPI, MCP) are separate NuGet packages.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can NpgsqlRest also serve my frontend (static files, SPA)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — enable the StaticFiles section (root defaults to wwwroot) and it serves your SPA or static site from the same host as the API. AuthorizePaths puts paths behind login (with UnauthorizedRedirectPath for the redirect), and ParseContentOptions can template user claims and allow-listed environment \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I install NpgsqlRest?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"See the Installation Guide — standalone executable (Linux/macOS/Windows), an npm package (npm i npgsqlrest), a Docker image, or NuGet.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I run it in Docker?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Remember that localhost inside the container is the container — point the connection string at host.docker.internal (or the compose service name) to reach your database.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I connect to my database?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Set the connection string in appsettings.json: See Connection Settings for all options.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What if NpgsqlRest won't start because the database is down?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"By default TestConnectionStrings: true opens a test connection at startup. If it fails, the client retries on a 1, 3, 6, 12-second sequence for transient errors (connection drops, timeouts), then exits with an error if all retries fail. To skip the startup test, set TestConnectionStrings: false, or \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use environment variables for configuration?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. With ParseEnvironmentVariables in the Config section (enabled by default), use {ENVVARNAME} placeholders in configuration values — optional by default, {!ENVVARNAME} for required (startup error when unset, since 3.17.0), or {!ENVVARNAME:fallback} for a fallback value when unset (since 3.21.0). \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I change the port, bind address, or enable HTTPS?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Set the top-level Urls option — the default is http://localhost:8080; use http://0.0.0.0:8080 to listen on all interfaces (semicolon-separate multiple URLs). HTTPS is enabled with the Ssl section (redirection and HSTS are on once enabled) and a certificate configured under Kestrel — PFX, PEM, or the\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My function doesn't appear as an endpoint\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Check these causes, most common first: 1. No HTTP annotation — since 3.17.0 the client defaults to CommentsMode: \\\\\\"OnlyAnnotated\\\\\\": a routine becomes an endpoint only if its comment contains an HTTP annotation (or a plugin annotation like @mcp). Add one — comment on function myfunc() is 'HTTP GET'; — \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My SQL file doesn't appear as an endpoint\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Same CommentsMode rule as functions — the file needs an HTTP annotation by default. Two additional file-specific causes: 1. SkipPattern — files matching SqlFileSource.SkipPattern (default \\\\\\".test.sql\\\\\\") are excluded from endpoint discovery; they're test files for the test runner. 2. A describe error w\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"An endpoint exists but I get 404 — why?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"A 404 for an existing path is almost always parameter matching: a request must supply values for all parameters without defaults, with matching names — otherwise no endpoint matches and the response is 404 (not 400). Check: 1. Parameter names are converted — puserid becomes pUserId with the default \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Why did my read-only function become a POST endpoint?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"For functions, the HTTP method is inferred from PostgreSQL volatility — and VOLATILE is PostgreSQL's default, so a plain function maps to a mutation unless it is declared STABLE or IMMUTABLE, its name starts with get, contains get, or ends with get. Fix: declare read functions STABLE (good practice \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Are parameters sent in the query string or the request body?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"By HTTP method: GET and DELETE endpoints read parameters from the query string; POST, PUT, and other methods read a JSON body. Override per endpoint with @requestparamtype (querystring or bodyjson), or globally with DefaultRequestParamType. Sending parameters the wrong way means no endpoint matches \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Why are parameter and column names camelCased? How do I turn that off?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"The default NameConverter converts snakecase PostgreSQL names to camelCase JSON/URL names. Set \\\\\\"CamelCaseNames\\\\\\": false in the NpgsqlRest section to keep names exactly as they are in the database.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My query returns one row — why do I get an array?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Endpoints return arrays by default. Annotate with @single to return the first row as a single JSON object, or combine with @nested for composite shapes. A single-column result set returns a flat value array ([\\\\\\"a\\\\\\",\\\\\\"b\\\\\\"]) — that's the UnnamedSingleColumnSet default in SQL File Source.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I return plain text, HTML, or CSV instead of JSON?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use @raw — the column values are written to the response verbatim, with @separator and @newline for delimiter control, plus a Content-Type response header: There is also a table format output mode for ready-made HTML tables and Excel exports.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I return a specific HTTP status code from SQL?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"raise exception 'message'; surfaces as HTTP 400 by default (SQLSTATE P0001), insufficient privilege (42501) as 403, and command timeouts as 504. The whole mapping is configurable — ErrorHandlingOptions maps any PostgreSQL SQLSTATE to any status code through named policies, so raise exception ... usi\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I set response headers like \`Content-Disposition\` or \`Set-Cookie\`?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Write plain Header-Name: value lines in the comment — the same way the CSV example above sets Content-Type. Values support {parameter} substitution, so a dynamic download filename is one line: Content-Disposition: attachment; filename={name}.csv. Repeated header names combine into one header. See Re\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can one SQL file run multiple statements?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — a multi-statement file executes as a single batch (one database round-trip) and returns a JSON object with one key per result set: {\\\\\\"result1\\\\\\": ..., \\\\\\"result2\\\\\\": ...}. Name the keys with @result, drop a statement's output with @skip (it still executes), or return 204 No Content with @void; BEGIN/\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I customize the endpoint URL path?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use the @path annotation — -- @path /custom/path in a SQL file, or the same line in a function comment. Versioning works the same way: @path /v2/orders.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I restrict access to an endpoint?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use @authorize, optionally with roles: -- @authorize admin, manager. Mind the default posture, though: the standalone client ships with RequiresAuthorization: true, so every endpoint already requires an authenticated user and @allowanonymous opts out per endpoint. Set NpgsqlRest.RequiresAuthorizatio\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I expose tables and views directly, without writing any SQL?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"That's deliberately not the default model — NpgsqlRest wants you to design the API surface. The closest thing is a one-line SQL file per operation (select from myview; is a complete endpoint file). If you want fully automatic table CRUD, the NpgsqlRest.CrudSource NuGet plugin exists for library user\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Named or positional parameters in SQL files — which should I use?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Named (:name, since 3.19.0) for almost everything — the placeholder is the parameter name, so no @param naming annotations are needed, and the same name used repeatedly (even across statements) is one parameter: GET /api/get-reports?fromDate=...&toDate=... — done. Positional ($1, $2) remains fully s\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I make a parameter optional?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Give it a default. Functions: the native DEFAULT clause. SQL files: the @param annotation — -- @param status default 'active' or -- @param label default null. A parameter without a default is required, and a request missing it gets a 404 (no matching endpoint).\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I get the authenticated user's ID into a query?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable claim-to-parameter mapping with @userparameters and use a parameter whose name matches a claim mapping (default: userid → the user-id claim). With named parameters this needs nothing else: The value comes from the authenticated principal — the client cannot send or override it. (With position\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I send an array parameter?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"In a query string, repeat the key: ?ids=1&ids=2&ids=3 binds a three-element PostgreSQL array to an int[] parameter. In a JSON body, use a JSON array: {\\\\\\"ids\\\\\\": [1, 2, 3]}. Careful: repeating a key for a non-array parameter concatenates the values into one string instead.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I pass NULL in a query string?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"By default an empty value (?p=) is an empty string, not NULL (QueryStringNullHandling: \\\\\\"Ignore\\\\\\"). Change it per endpoint with @querystringnullhandling — emptystring makes ?p= mean NULL, nullliteral makes ?p=null mean NULL — or set the global default. For NULLs in text responses, @responsenull choose\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I read HTTP request headers in my SQL?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Add a json or text parameter named headers with a null default — the default RequestHeadersMode: \\\\\\"Parameter\\\\\\" fills it with all request headers as JSON. The Context mode makes headers readable anywhere via currentsetting('request.headers', true) instead. Per endpoint: @requestheadersmode.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I receive a raw request body (webhooks)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use @bodyparametername — the entire raw body (text, JSON, or bytea) is routed into that one parameter, and any other parameters automatically move to the query string.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I validate parameters before they reach the database?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — @validate using , runs immediately after parsing, before any database connection is opened. Built-in rules: notnull, notempty, required, email; custom Regex/MinLength/MaxLength rules with their own status codes and messages are defined in ValidationOptions. See Validation and @validate.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Error: \\\\\\"could not determine data type of parameter\\\\\\"\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"PostgreSQL couldn't infer the parameter's type from context (classic case: select setconfig('key', :value, true)). Give it a type hint: -- @param :value text (or -- @param $1 value text positionally), or add an inline cast in the SQL (:value::text). ---\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What authentication methods are supported?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Cookie-based auth, JWT Bearer tokens, Microsoft Bearer tokens, HTTP Basic Auth, Passkeys/WebAuthn (FIDO2), and external OAuth providers (Google, GitHub, LinkedIn, Microsoft, Facebook). All can be enabled simultaneously. See Authentication config.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I set up JWT authentication?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"See the Multiple Auth Schemes blog post for a complete walkthrough including login endpoints and RBAC.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I create a login endpoint?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Annotate a routine or SQL file with @login (usually together with @allowanonymous). It returns one row: a few special columns (status, scheme, body, hash) control the response, and every other column becomes a claim on the signed-in user — no row returned means 401. Verify the password yourself in S\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I log users out?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Annotate an endpoint with @logout. A void routine signs the caller out of all schemes; returned values are treated as scheme names to sign out of selectively.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I hash passwords when creating users?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Use -- @param hashedpassword is hash of password — the target parameter receives a PBKDF2-SHA256 hash of the source parameter before the routine runs, compatible with @login's built-in verification. The CLI can hash too: npgsqlrest --hash . See parameter hashing.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I add social login (Google, GitHub, Microsoft…)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable Auth.External and add a provider block with ClientId and ClientSecret — Google, GitHub, LinkedIn, Microsoft, and Facebook are pre-configured; custom providers just set their URLs. After the OAuth flow, NpgsqlRest calls your configured LoginCommand function with the provider data, and its resu\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My SPA on a different domain loses the session cookie — why?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Browsers drop cookies on cross-site requests unless the cookie is explicitly marked for it: set Auth.CookieSameSite: \\\\\\"None\\\\\\" together with Auth.CookieSecure: \\\\\\"Always\\\\\\" (and typically CookieDomain), and enable CORS with AllowCredentials: true and explicit origins. See Auth config and CORS. ---\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I push real-time events to the browser?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Server-Sent Events: annotate a routine with @sse and every raise info it makes is broadcast to subscribers connected to the endpoint's stream URL (/info by default). Control who receives events with @ssescope — all, authorize [roles], or matching. See the SSE guide and the real-time chat blog post.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I accept file uploads?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable UploadOptions and annotate the endpoint with @upload. Four handlers: largeobject (default — PostgreSQL Large Objects), filesystem, and csv/excel, which parse the file and run a SQL command per row (bulk ingestion without client code). Upload metadata arrives in a json parameter, and everythin\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can my SQL call an external HTTP API?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — HTTP Custom Types: create a composite type whose comment describes a request (GET https://api.example.com/{id}, headers, body), take it as a function parameter, and NpgsqlRest executes the call and fills the type's fields (body, statuscode, success, …) before your function runs. Requires HttpC\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can NpgsqlRest forward requests to another service (reverse proxy)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — @proxy forwards the request to an upstream URL and streams the response back without touching the database; declare proxy parameters to transform the upstream response in SQL instead. @proxyout is the reverse: run your routine first, then send its result upstream (PDF rendering, ML inference, \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I expose functions as AI tools (MCP)?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable McpOptions and annotate routines with @mcp — only annotated routines are exposed, on a single /mcp endpoint (streamable HTTP). @mcp without an HTTP annotation makes a tool-only routine with no REST route, and @authorize roles are enforced on tool calls. Since 3.20.0, McpOptions.ToolSchemas ca\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can it generate a client — TypeScript, Dart, \`.http\` files, OpenAPI?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"All of them, regenerated on every watch cycle: ClientCodeGen emits typed TypeScript fetch modules with interfaces (and, since 3.20.0, optional TanStack Query hooks via ReactQuery), DartClientCodeGen (3.20.0) emits Dart modules for Flutter, HttpFileOptions writes ready-to-run .http files, and OpenApi\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I test my endpoints?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"With the built-in SQL test runner (since 3.19.0): write tests as plain .sql files and run npgsqlrest ./config.json --test. A test inserts fixtures, invokes a real endpoint in-process (full pipeline: routing, auth, parameter binding, serialization), asserts on the captured response with ordinary SQL,\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can tests run against a temporary database instead of my real one?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — that's the recommended CI setup. Setup steps create (and Teardown drops) a uniquely named database (apptest{rnd5}), migrations run as a step, and TestRunner.ConnectionName points the whole run at it. Template databases give per-test clones for perfect isolation. See the scenario catalog in the\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My test fixtures need half the database inserted first — is there a better way?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes, and it's pure PostgreSQL: declare your foreign keys deferrable, then start the test with set constraints all deferred;. Deferred constraints are checked at COMMIT — and a test that ends in rollback never commits, so you can insert only the rows the test is about, in any order, referencing rows \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is there a watch mode?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Two, with one flag. npgsqlrest ... --test --watch re-runs tests on changes — a changed test re-runs alone in milliseconds; a changed endpoint file or database routine rebuilds the endpoints in-process and re-runs everything, reporting exactly which endpoints appeared or dropped; Ctrl+C still tears t\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How fast is it?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Independent-methodology benchmarks measure thousands of requests per second on a single host — see the July 2026 benchmark series for detailed comparisons against PostgREST, Go, Rust, Spring Boot, FastAPI, and others under equalized conditions, including the methodology, per-framework analysis, and \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I enable caching?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Annotate with @cached (+ @cacheexpiresin 5 minutes). The backend (Memory, Redis, or HybridCache) is configured in Cache Options; per-user and per-parameter cache keys are supported. For conditional or tiered rules (\\\\\\"skip caching for admins\\\\\\", \\\\\\"shorter TTL for open-ended queries\\\\\\"), bundle settings int\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I enable response compression?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"See Response Compression.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I set up rate limiting?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Define policies in Rate Limiter config and apply them per endpoint with @ratelimiterpolicy.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Should I use the AOT or the JIT Docker image?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"The default AOT image (~60 MB compressed) starts instantly — best for development, CLI use, and scale-to-zero deployments. The JIT variant (vbilopav/npgsqlrest:latest-jit) is 50–100% faster under sustained high concurrency, at the cost of slower cold start and a ~110 MB compressed image — recommende\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I stream very large result sets?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Responses are flushed every 25 rows by default. @bufferrows 0 writes each row as it arrives (constant memory, immediate first byte); higher values trade memory for throughput. ---\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My browser app gets CORS errors — how do I allow my frontend origin?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable the Cors section and list origins explicitly. AllowCredentials defaults to false — cookie-based auth needs it true, together with explicit AllowedOrigins (browsers reject combined with credentials): See CORS.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Behind nginx / Cloudflare the client IP is wrong\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable the ForwardedHeaders section so X-Forwarded-For/-Proto are honored — this affects logs, rate limiting, and the request.ipaddress context value. Set ForwardLimit to your proxy-chain depth and restrict trust with KnownProxies/KnownNetworks; with both lists empty, the headers are accepted from a\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I run behind PgBouncer / RDS Proxy / Supabase Pooler in transaction mode?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — set NpgsqlRest.WrapInTransaction: true. It wraps every request in BEGIN…COMMIT, which keeps setconfig state (claims, headers, user context) local to the request instead of leaking across pooled backends. Required for any pooler in transaction mode. See NpgsqlRest Options.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is there a health endpoint for Kubernetes or load balancers?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Enable HealthChecks: /health (overall), /health/ready (includes a PostgreSQL connectivity check), and /health/live (no database check — so a database outage doesn't restart your pods). See Health Checks.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I route endpoints to a read replica or a second database?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — two mechanisms, depending on whether the databases have the same routines. For identical databases (read replicas, shards): define multiple named entries in ConnectionStrings, set NpgsqlRest.UseMultipleConnections: true, and pick per endpoint with @connection — metadata is still read once, and\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Does it retry transient errors?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Two layers, both on by default. Connection failures (startup included) retry on a 1, 3, 6, 12-second sequence, so the server survives the database starting after it does. Command execution retries transient SQLSTATEs — serialization failures (40001), deadlocks (40P01), dropped connections — on a 0, \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I see which endpoints are created and what options they have?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Set the NpgsqlRest log level to Debug — every endpoint logs as it is created, including which annotations were applied: Or list them without starting the server: npgsqlrest --endpoints.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I log the SQL each endpoint executes at runtime?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Two settings: \\\\\\"LogCommands\\\\\\": true in the NpgsqlRest section opts in, and the NpgsqlRest channel must be at Verbose (commands log at trace level): Add \\\\\\"LogCommandParameters\\\\\\": true to include parameter values (mind the sensitive-data implications in production — @securitysensitive obfuscates a specifi\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I see the metadata queries NpgsqlRest runs at startup?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Set the NpgsqlRest log level to Verbose — includes everything from Debug plus the raw pgcatalog discovery queries and the SQL-file describe phase. Useful when a function or file isn't being discovered and you need to see the underlying query and its filters.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I completely silence a logger?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Since 3.19.0 any Log:MinimalLevels entry accepts \\\\\\"Off\\\\\\" (aliases \\\\\\"None\\\\\\", \\\\\\"Silent\\\\\\"): Each named logger is independent — handy for muting the application channels while watching the test runner's NpgsqlRestTest channel.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Why do my RAISE messages appear in the server log?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"LogConnectionNoticeEvents is on by default — raise info/notice/warning from executing routines is written to the application log (the same mechanism that powers SSE). Set it to false in the NpgsqlRest section to silence them, or tune the format with LogConnectionNoticeEventsMode. See the Logging Gui\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I validate the configuration without starting the server?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"npgsqlrest --validate checks configuration keys and database connectivity, exiting 0 on success and 1 on failure — CI-friendly. Related: --config prints the fully resolved annotated configuration, --annotations lists every supported comment annotation as JSON, and --endpoints lists the endpoints tha\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use the CLI to generate password hashes?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes — npgsqlrest --hash generates a PBKDF2-SHA256 hash compatible with @login and password parameters. For HTTP Basic auth, npgsqlrest --basicauth outputs the header value to add to a request. ---\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Every endpoint returns 401 Unauthorized\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"That is the default posture, not a bug: the standalone client ships with RequiresAuthorization: true, so endpoints require an authenticated user unless annotated otherwise. Add @allowanonymous to public endpoints, or set NpgsqlRest.RequiresAuthorization to false and protect endpoints individually wi\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Startup warning: \\\\\\"Unknown configuration key\\\\\\"\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Almost always a typo in appsettings.json — keys are validated at startup. Run npgsqlrest --config to print the complete annotated configuration, or use the published JSON schema for editor autocompletion.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Error: \\\\\\"permission denied for schema\\\\\\"\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"The database user lacks USAGE on the schema: This is also a feature: run the server as a least-privilege role and endpoints can only do what that role can do.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Timeout errors (504 Gateway Timeout)\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Adjust the command timeout per endpoint with @commandtimeout 2 minutes, or globally in configuration.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"My POST body seems ignored — the endpoint returns 404\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Request bodies are read as JSON regardless of the Content-Type header — there is no content-type validation, and form-encoded/form-multipart bodies are never parsed (multipart files are only for @upload endpoints). A malformed JSON body logs a warning (Could not parse JSON body ...) and the request \\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"413 Payload Too Large\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Kestrel caps request bodies at 30,000,000 bytes (~28.6 MB) by default — large uploads hit this before any NpgsqlRest setting. Raise Kestrel.Limits.MaxRequestBodySize in Server settings.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Timestamps shifted after upgrading to 3.16+\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Since 3.16.0, timestamps in JSON are treated as UTC by default (naive ISO strings assumed UTC, offset strings converted), so stored values no longer depend on the host's timezone. If you relied on the old host-local parsing, NpgsqlRest.JsonTimestampsAreUtc: false restores it — but treat that as a co\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Encrypted data is unreadable after restart\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Data Protection keys default to in-memory on Linux — configure persistent storage: See Data Protection config.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Leftover \`*_abcde\` test databases\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"The test runner drops its {rnd}-named databases on every exit path it can intercept — including Ctrl+C, SIGTERM, and hard startup errors. Leftovers mean a run was killed with SIGKILL (nothing can intercept that) or ran with Keep: true. Drop them manually:\\"}}]}"]]},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1782480183000}`),i={name:"guide/faq.md"};function o(r,e,l,d,h,p){return s(),a("div",null,e[0]||(e[0]=[n(`<h1 id="faq-troubleshooting" tabindex="-1">FAQ &amp; Troubleshooting <a class="header-anchor" href="#faq-troubleshooting" aria-label="Permalink to &quot;FAQ &amp; Troubleshooting&quot;">​</a></h1><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="what-is-npgsqlrest" tabindex="-1">What is NpgsqlRest? <a class="header-anchor" href="#what-is-npgsqlrest" aria-label="Permalink to &quot;What is NpgsqlRest?&quot;">​</a></h3><p>NpgsqlRest is a self-contained executable that connects to PostgreSQL and automatically creates REST API endpoints from plain SQL script files, database functions, and procedures. No code generation step, no ORM — just SQL.</p><h3 id="what-postgresql-versions-are-supported" tabindex="-1">What PostgreSQL versions are supported? <a class="header-anchor" href="#what-postgresql-versions-are-supported" aria-label="Permalink to &quot;What PostgreSQL versions are supported?&quot;">​</a></h3><p>PostgreSQL 13 and newer. Discovery uses standard <code>pg_catalog</code> views that are stable across PostgreSQL versions.</p><h3 id="what-net-version-is-required" tabindex="-1">What .NET version is required? <a class="header-anchor" href="#what-net-version-is-required" aria-label="Permalink to &quot;What .NET version is required?&quot;">​</a></h3><p>None, for most users — the standalone executable and the Docker image are fully self-contained (AOT-compiled). The NuGet library targets .NET 10.</p><h3 id="is-it-safe-from-sql-injection" tabindex="-1">Is it safe from SQL injection? <a class="header-anchor" href="#is-it-safe-from-sql-injection" aria-label="Permalink to &quot;Is it safe from SQL injection?&quot;">​</a></h3><p>Yes, by construction. Client-supplied values are <strong>always</strong> sent as PostgreSQL protocol parameters — never concatenated into SQL text. The SQL that runs is the SQL you wrote in the file, function, or procedure; a request can only choose parameter <em>values</em>, never SQL fragments. There is no query-building layer to inject into (unlike REST-to-SQL translators that construct queries from URLs).</p><h3 id="how-does-npgsqlrest-compare-to-postgrest-or-supabase" tabindex="-1">How does NpgsqlRest compare to PostgREST or Supabase? <a class="header-anchor" href="#how-does-npgsqlrest-compare-to-postgrest-or-supabase" aria-label="Permalink to &quot;How does NpgsqlRest compare to PostgREST or Supabase?&quot;">​</a></h3><p>See the detailed <a href="/blog/npgsqlrest-vs-postgrest-supabase-comparison.html">comparison blog post</a> for a full feature-by-feature breakdown. The short version: PostgREST turns your <em>tables</em> into an API you query from the client; NpgsqlRest turns your <em>SQL</em> (files, functions, procedures) into an API you design.</p><h3 id="can-i-use-it-inside-an-existing-asp-net-core-application" tabindex="-1">Can I use it inside an existing ASP.NET Core application? <a class="header-anchor" href="#can-i-use-it-inside-an-existing-asp-net-core-application" aria-label="Permalink to &quot;Can I use it inside an existing ASP.NET Core application?&quot;">​</a></h3><p>Yes — the standalone executable is a wrapper around the <code>NpgsqlRest</code> NuGet middleware. In your own app: <code>app.UseNpgsqlRest(new NpgsqlRestOptions(connectionString) { ... })</code>. The plugins (SQL file source, TypeScript client, Dart client, OpenAPI, MCP) are separate NuGet packages.</p><h3 id="can-npgsqlrest-also-serve-my-frontend-static-files-spa" tabindex="-1">Can NpgsqlRest also serve my frontend (static files, SPA)? <a class="header-anchor" href="#can-npgsqlrest-also-serve-my-frontend-static-files-spa" aria-label="Permalink to &quot;Can NpgsqlRest also serve my frontend (static files, SPA)?&quot;">​</a></h3><p>Yes — enable the <code>StaticFiles</code> section (root defaults to <code>wwwroot</code>) and it serves your SPA or static site from the same host as the API. <code>AuthorizePaths</code> puts paths behind login (with <code>UnauthorizedRedirectPath</code> for the redirect), and <code>ParseContentOptions</code> can template user claims and allow-listed environment variables into HTML at serve time — per-environment SPA config without a build step. See <a href="/config/static-files.html">Static Files</a>.</p><hr><h2 id="installation-setup" tabindex="-1">Installation &amp; Setup <a class="header-anchor" href="#installation-setup" aria-label="Permalink to &quot;Installation &amp; Setup&quot;">​</a></h2><h3 id="how-do-i-install-npgsqlrest" tabindex="-1">How do I install NpgsqlRest? <a class="header-anchor" href="#how-do-i-install-npgsqlrest" aria-label="Permalink to &quot;How do I install NpgsqlRest?&quot;">​</a></h3><p>See the <a href="/guide/installation.html">Installation Guide</a> — standalone executable (Linux/macOS/Windows), an npm package (<code>npm i npgsqlrest</code>), a Docker image, or NuGet.</p><h3 id="how-do-i-run-it-in-docker" tabindex="-1">How do I run it in Docker? <a class="header-anchor" href="#how-do-i-run-it-in-docker" aria-label="Permalink to &quot;How do I run it in Docker?&quot;">​</a></h3><details class="code-collapsible" open><summary>sh</summary><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">docker</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> run</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> --name</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> npgsqlrest</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> -p</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> 8080:8080</span><span style="--shiki-light:#EA76CB;--shiki-dark:#F5C2E7;"> \\</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">  -v</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> ./appsettings.json:/app/appsettings.json</span><span style="--shiki-light:#EA76CB;--shiki-dark:#F5C2E7;"> \\</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">  vbilopav/npgsqlrest:latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p>Remember that <code>localhost</code> inside the container is the container — point the connection string at <code>host.docker.internal</code> (or the compose service name) to reach your database.</p><h3 id="how-do-i-connect-to-my-database" tabindex="-1">How do I connect to my database? <a class="header-anchor" href="#how-do-i-connect-to-my-database" aria-label="Permalink to &quot;How do I connect to my database?&quot;">​</a></h3><p>Set the connection string in <code>appsettings.json</code>:</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">ConnectionStrings</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Default</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Host=localhost;Port=5432;Database=mydb;Username=postgres;Password=postgres&quot;</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p>See <a href="/config/connection.html">Connection Settings</a> for all options.</p><h3 id="what-if-npgsqlrest-won-t-start-because-the-database-is-down" tabindex="-1">What if NpgsqlRest won&#39;t start because the database is down? <a class="header-anchor" href="#what-if-npgsqlrest-won-t-start-because-the-database-is-down" aria-label="Permalink to &quot;What if NpgsqlRest won&#39;t start because the database is down?&quot;">​</a></h3><p>By default <code>TestConnectionStrings: true</code> opens a test connection at startup. If it fails, the client retries on a 1, 3, 6, 12-second sequence for transient errors (connection drops, timeouts), then exits with an error if all retries fail. To skip the startup test, set <code>TestConnectionStrings: false</code>, or disable retries with <code>ConnectionRetryOptions.Enabled: false</code>. This is useful when you want the server to start even if PostgreSQL isn&#39;t ready yet.</p><h3 id="can-i-use-environment-variables-for-configuration" tabindex="-1">Can I use environment variables for configuration? <a class="header-anchor" href="#can-i-use-environment-variables-for-configuration" aria-label="Permalink to &quot;Can I use environment variables for configuration?&quot;">​</a></h3><p>Yes. With <code>ParseEnvironmentVariables</code> in the <code>Config</code> section (enabled by default), use <code>{ENV_VAR_NAME}</code> placeholders in configuration values — optional by default, <code>{!ENV_VAR_NAME}</code> for required (startup error when unset, since 3.17.0), or <code>{!ENV_VAR_NAME:fallback}</code> for a fallback value when unset (since 3.21.0). A <code>./.env</code> file is loaded automatically since 3.21.0 (the <code>EnvFile</code> option; real environment variables always win over the file — set it to <code>null</code> to disable). Any setting can also be overridden on the command line: <code>npgsqlrest --npgsqlrest:urlpathprefix=/v1</code>.</p><h3 id="how-do-i-change-the-port-bind-address-or-enable-https" tabindex="-1">How do I change the port, bind address, or enable HTTPS? <a class="header-anchor" href="#how-do-i-change-the-port-bind-address-or-enable-https" aria-label="Permalink to &quot;How do I change the port, bind address, or enable HTTPS?&quot;">​</a></h3><p>Set the top-level <code>Urls</code> option — the default is <code>http://localhost:8080</code>; use <code>http://0.0.0.0:8080</code> to listen on all interfaces (semicolon-separate multiple URLs). HTTPS is enabled with the <code>Ssl</code> section (redirection and HSTS are on once enabled) and a certificate configured under <code>Kestrel</code> — PFX, PEM, or the Windows certificate store. See <a href="/config/server.html">Server settings</a>.</p><hr><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><h3 id="my-function-doesn-t-appear-as-an-endpoint" tabindex="-1">My function doesn&#39;t appear as an endpoint <a class="header-anchor" href="#my-function-doesn-t-appear-as-an-endpoint" aria-label="Permalink to &quot;My function doesn&#39;t appear as an endpoint&quot;">​</a></h3><p>Check these causes, most common first:</p><ol><li><strong>No <code>HTTP</code> annotation</strong> — since 3.17.0 the client defaults to <code>CommentsMode: &quot;OnlyAnnotated&quot;</code>: a routine becomes an endpoint <strong>only if its comment contains an HTTP annotation</strong> (or a plugin annotation like <code>@mcp</code>). Add one — <code>comment on function my_func() is &#39;HTTP GET&#39;;</code> — or set <code>CommentsMode: &quot;ParseAll&quot;</code> to expose everything discovered.</li><li><strong>Schema not included</strong>: by default only the <code>public</code> schema is scanned. Adjust <code>SchemaSimilarTo</code> in <a href="/config/npgsqlrest.html">NpgsqlRest Options</a>.</li><li><strong>Insufficient privileges</strong>: the connection&#39;s database user needs <code>EXECUTE</code> on the function and <code>USAGE</code> on the schema.</li><li><strong>A <code>@disabled</code> annotation</strong> on the routine.</li><li><strong>Check the logs</strong>: run with the <code>NpgsqlRest</code> log level at <code>Debug</code> to see what was discovered and skipped.</li></ol><h3 id="my-sql-file-doesn-t-appear-as-an-endpoint" tabindex="-1">My SQL file doesn&#39;t appear as an endpoint <a class="header-anchor" href="#my-sql-file-doesn-t-appear-as-an-endpoint" aria-label="Permalink to &quot;My SQL file doesn&#39;t appear as an endpoint&quot;">​</a></h3><p>Same <code>CommentsMode</code> rule as functions — the file needs an <code>HTTP</code> annotation by default. Two additional file-specific causes:</p><ol><li><strong><code>SkipPattern</code></strong> — files matching <code>SqlFileSource.SkipPattern</code> (default <code>&quot;*.test.sql&quot;</code>) are excluded from endpoint discovery; they&#39;re test files for the <a href="/guide/testing.html">test runner</a>.</li><li><strong>A describe error with <code>ErrorMode: &quot;Skip&quot;</code></strong> — the file failed type-checking against the database and was skipped with a logged error. (<code>ErrorMode: &quot;Exit&quot;</code>, the default, would have stopped startup and shown it.)</li></ol><h3 id="an-endpoint-exists-but-i-get-404-—-why" tabindex="-1">An endpoint exists but I get 404 — why? <a class="header-anchor" href="#an-endpoint-exists-but-i-get-404-—-why" aria-label="Permalink to &quot;An endpoint exists but I get 404 — why?&quot;">​</a></h3><p>A 404 for an existing path is almost always <strong>parameter matching</strong>: a request must supply values for <strong>all parameters without defaults</strong>, with <strong>matching names</strong> — otherwise no endpoint matches and the response is 404 (not 400). Check:</p><ol><li><strong>Parameter names are converted</strong> — <code>p_user_id</code> becomes <code>pUserId</code> with the default camelCase converter. The generated <a href="/config/codegen.html">TypeScript client</a> or <a href="/config/http-files.html">HTTP file</a> always shows the exact names.</li><li><strong>Missing required parameter</strong> — give it a default (<code>@param name default null</code> in SQL files, <code>DEFAULT</code> in function signatures) to make it optional.</li><li><strong>The path prefix</strong> — the full path includes <code>UrlPathPrefix</code> (default <code>/api</code>).</li><li><strong>The HTTP method</strong> — <code>select</code> files/functions map to GET by default; mutations map to PUT/POST/DELETE.</li></ol><h3 id="why-did-my-read-only-function-become-a-post-endpoint" tabindex="-1">Why did my read-only function become a POST endpoint? <a class="header-anchor" href="#why-did-my-read-only-function-become-a-post-endpoint" aria-label="Permalink to &quot;Why did my read-only function become a POST endpoint?&quot;">​</a></h3><p>For functions, the HTTP method is inferred from PostgreSQL <strong>volatility</strong> — and <code>VOLATILE</code> is PostgreSQL&#39;s default, so a plain function maps to a mutation unless it is declared <code>STABLE</code> or <code>IMMUTABLE</code>, its name starts with <code>get_</code>, contains <code>_get_</code>, or ends with <code>_get</code>. Fix: declare read functions <code>STABLE</code> (good practice anyway), use a <code>get_</code> name, or state the method explicitly in the comment: <code>HTTP GET</code>. See <a href="/guide/annotations.html">Comment Annotations</a>.</p><h3 id="are-parameters-sent-in-the-query-string-or-the-request-body" tabindex="-1">Are parameters sent in the query string or the request body? <a class="header-anchor" href="#are-parameters-sent-in-the-query-string-or-the-request-body" aria-label="Permalink to &quot;Are parameters sent in the query string or the request body?&quot;">​</a></h3><p>By HTTP method: GET and DELETE endpoints read parameters from the <strong>query string</strong>; POST, PUT, and other methods read a <strong>JSON body</strong>. Override per endpoint with <a href="/annotations/request-param-type.html"><code>@request_param_type</code></a> (<code>query_string</code> or <code>body_json</code>), or globally with <code>DefaultRequestParamType</code>. Sending parameters the wrong way means no endpoint matches — a 404, not a 400.</p><h3 id="why-are-parameter-and-column-names-camelcased-how-do-i-turn-that-off" tabindex="-1">Why are parameter and column names camelCased? How do I turn that off? <a class="header-anchor" href="#why-are-parameter-and-column-names-camelcased-how-do-i-turn-that-off" aria-label="Permalink to &quot;Why are parameter and column names camelCased? How do I turn that off?&quot;">​</a></h3><p>The default <code>NameConverter</code> converts <code>snake_case</code> PostgreSQL names to <code>camelCase</code> JSON/URL names. Set <code>&quot;CamelCaseNames&quot;: false</code> in the <code>NpgsqlRest</code> section to keep names exactly as they are in the database.</p><h3 id="my-query-returns-one-row-—-why-do-i-get-an-array" tabindex="-1">My query returns one row — why do I get an array? <a class="header-anchor" href="#my-query-returns-one-row-—-why-do-i-get-an-array" aria-label="Permalink to &quot;My query returns one row — why do I get an array?&quot;">​</a></h3><p>Endpoints return arrays by default. Annotate with <a href="/annotations/single.html"><code>@single</code></a> to return the first row as a single JSON object, or combine with <code>@nested</code> for composite shapes. A single-column result set returns a flat value array (<code>[&quot;a&quot;,&quot;b&quot;]</code>) — that&#39;s the <code>UnnamedSingleColumnSet</code> default in <a href="/config/sql-file-source.html">SQL File Source</a>.</p><h3 id="how-do-i-return-plain-text-html-or-csv-instead-of-json" tabindex="-1">How do I return plain text, HTML, or CSV instead of JSON? <a class="header-anchor" href="#how-do-i-return-plain-text-html-or-csv-instead-of-json" aria-label="Permalink to &quot;How do I return plain text, HTML, or CSV instead of JSON?&quot;">​</a></h3><p>Use <a href="/annotations/raw.html"><code>@raw</code></a> — the column values are written to the response verbatim, with <a href="/annotations/separator.html"><code>@separator</code> and <code>@new_line</code></a> for delimiter control, plus a <code>Content-Type</code> response header:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @raw</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @separator ,</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @new_line \\n</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- Content-Type: text/csv</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">select</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> id, </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">name</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">, price </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">from</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> products;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></details><p>There is also a <a href="/config/table-format.html">table format</a> output mode for ready-made HTML tables and Excel exports.</p><h3 id="how-do-i-return-a-specific-http-status-code-from-sql" tabindex="-1">How do I return a specific HTTP status code from SQL? <a class="header-anchor" href="#how-do-i-return-a-specific-http-status-code-from-sql" aria-label="Permalink to &quot;How do I return a specific HTTP status code from SQL?&quot;">​</a></h3><p><code>raise exception &#39;message&#39;;</code> surfaces as HTTP 400 by default (SQLSTATE <code>P0001</code>), insufficient privilege (<code>42501</code>) as 403, and command timeouts as 504. The whole mapping is configurable — <code>ErrorHandlingOptions</code> maps any PostgreSQL SQLSTATE to any status code through named policies, so <code>raise exception ... using errcode = &#39;...&#39;</code> plus a policy entry gives full status control from SQL (e.g. map <code>23505</code> unique violations to 409). Apply a policy per endpoint with <a href="/annotations/error-code-policy.html"><code>@error_code_policy</code></a>; unmapped errors return 500. See <a href="/config/error-handling.html">Error Handling</a>.</p><h3 id="how-do-i-set-response-headers-like-content-disposition-or-set-cookie" tabindex="-1">How do I set response headers like <code>Content-Disposition</code> or <code>Set-Cookie</code>? <a class="header-anchor" href="#how-do-i-set-response-headers-like-content-disposition-or-set-cookie" aria-label="Permalink to &quot;How do I set response headers like \`Content-Disposition\` or \`Set-Cookie\`?&quot;">​</a></h3><p>Write plain <code>Header-Name: value</code> lines in the comment — the same way the CSV example above sets <code>Content-Type</code>. Values support <code>{parameter}</code> substitution, so a dynamic download filename is one line: <code>Content-Disposition: attachment; filename={name}.csv</code>. Repeated header names combine into one header. See <a href="/annotations/response-headers.html">Response Headers</a> and <a href="/annotations/parameter-substitution.html">parameter substitution</a>.</p><h3 id="can-one-sql-file-run-multiple-statements" tabindex="-1">Can one SQL file run multiple statements? <a class="header-anchor" href="#can-one-sql-file-run-multiple-statements" aria-label="Permalink to &quot;Can one SQL file run multiple statements?&quot;">​</a></h3><p>Yes — a multi-statement file executes as a single batch (one database round-trip) and returns a JSON object with one key per result set: <code>{&quot;result1&quot;: ..., &quot;result2&quot;: ...}</code>. Name the keys with <a href="/annotations/result-name.html"><code>@result</code></a>, drop a statement&#39;s output with <a href="/annotations/skip.html"><code>@skip</code></a> (it still executes), or return <code>204 No Content</code> with <a href="/annotations/void.html"><code>@void</code></a>; <code>BEGIN</code>/<code>COMMIT</code>/<code>SET</code> statements are hidden automatically. All statements share the same parameters. See <a href="/guide/sql-files.html">SQL File Endpoints</a>.</p><h3 id="how-do-i-customize-the-endpoint-url-path" tabindex="-1">How do I customize the endpoint URL path? <a class="header-anchor" href="#how-do-i-customize-the-endpoint-url-path" aria-label="Permalink to &quot;How do I customize the endpoint URL path?&quot;">​</a></h3><p>Use the <a href="/annotations/path.html"><code>@path</code></a> annotation — <code>-- @path /custom/path</code> in a SQL file, or the same line in a function comment. Versioning works the same way: <code>@path /v2/orders</code>.</p><h3 id="how-do-i-restrict-access-to-an-endpoint" tabindex="-1">How do I restrict access to an endpoint? <a class="header-anchor" href="#how-do-i-restrict-access-to-an-endpoint" aria-label="Permalink to &quot;How do I restrict access to an endpoint?&quot;">​</a></h3><p>Use <a href="/annotations/authorize.html"><code>@authorize</code></a>, optionally with roles: <code>-- @authorize admin, manager</code>. Mind the default posture, though: the standalone client ships with <code>RequiresAuthorization: true</code>, so <strong>every endpoint already requires an authenticated user</strong> and <a href="/annotations/allow-anonymous.html"><code>@allow_anonymous</code></a> opts out per endpoint. Set <code>NpgsqlRest.RequiresAuthorization</code> to <code>false</code> for public-by-default endpoints where <code>@authorize</code> opts in (that is the NuGet library&#39;s default).</p><h3 id="can-i-expose-tables-and-views-directly-without-writing-any-sql" tabindex="-1">Can I expose tables and views directly, without writing any SQL? <a class="header-anchor" href="#can-i-expose-tables-and-views-directly-without-writing-any-sql" aria-label="Permalink to &quot;Can I expose tables and views directly, without writing any SQL?&quot;">​</a></h3><p>That&#39;s deliberately not the default model — NpgsqlRest wants you to <em>design</em> the API surface. The closest thing is a one-line SQL file per operation (<code>select * from my_view;</code> is a complete endpoint file). If you want fully automatic table CRUD, the <code>NpgsqlRest.CrudSource</code> NuGet plugin exists for library users, but plain SQL files are the recommended path.</p><hr><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><h3 id="named-or-positional-parameters-in-sql-files-—-which-should-i-use" tabindex="-1">Named or positional parameters in SQL files — which should I use? <a class="header-anchor" href="#named-or-positional-parameters-in-sql-files-—-which-should-i-use" aria-label="Permalink to &quot;Named or positional parameters in SQL files — which should I use?&quot;">​</a></h3><p>Named (<code>:name</code>, since 3.19.0) for almost everything — the placeholder is the parameter name, so no <code>@param</code> naming annotations are needed, and the same name used repeatedly (even across statements) is one parameter:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">select</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> id, title </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">from</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> reports</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">where</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> created_at </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">between</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> :from_date </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">and</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> :to_date;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p><code>GET /api/get-reports?fromDate=...&amp;toDate=...</code> — done. Positional (<code>$1</code>, <code>$2</code>) remains fully supported; one style per file. See <a href="/guide/sql-files.html#parameters">SQL File Endpoints — Parameters</a>.</p><h3 id="how-do-i-make-a-parameter-optional" tabindex="-1">How do I make a parameter optional? <a class="header-anchor" href="#how-do-i-make-a-parameter-optional" aria-label="Permalink to &quot;How do I make a parameter optional?&quot;">​</a></h3><p>Give it a default. Functions: the native <code>DEFAULT</code> clause. SQL files: the <code>@param</code> annotation — <code>-- @param status default &#39;active&#39;</code> or <code>-- @param label default null</code>. A parameter without a default is required, and a request missing it gets a 404 (no matching endpoint).</p><h3 id="how-do-i-get-the-authenticated-user-s-id-into-a-query" tabindex="-1">How do I get the authenticated user&#39;s ID into a query? <a class="header-anchor" href="#how-do-i-get-the-authenticated-user-s-id-into-a-query" aria-label="Permalink to &quot;How do I get the authenticated user&#39;s ID into a query?&quot;">​</a></h3><p>Enable claim-to-parameter mapping with <a href="/annotations/user-parameters.html"><code>@user_parameters</code></a> and use a parameter whose <strong>name matches a claim mapping</strong> (default: <code>_user_id</code> → the user-id claim). With named parameters this needs nothing else:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @authorize</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @user_parameters</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">select</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> id, total, </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">status</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">from</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> orders</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">where</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> user_id </span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">=</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> :_user_id;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></details><p>The value comes from the authenticated principal — the client cannot send or override it. (With positional parameters, add <code>-- @param $1 _user_id</code> to give <code>$1</code> the mapped name.) To read claims as session settings instead of parameters, <a href="/annotations/user-context.html"><code>@user_context</code></a> exposes them to <code>current_setting(&#39;request.user_id&#39;, true)</code>, <code>request.user_roles</code>, <code>request.ip_address</code>, and friends.</p><h3 id="how-do-i-send-an-array-parameter" tabindex="-1">How do I send an array parameter? <a class="header-anchor" href="#how-do-i-send-an-array-parameter" aria-label="Permalink to &quot;How do I send an array parameter?&quot;">​</a></h3><p>In a query string, repeat the key: <code>?ids=1&amp;ids=2&amp;ids=3</code> binds a three-element PostgreSQL array to an <code>int[]</code> parameter. In a JSON body, use a JSON array: <code>{&quot;ids&quot;: [1, 2, 3]}</code>. Careful: repeating a key for a <em>non-array</em> parameter concatenates the values into one string instead.</p><h3 id="how-do-i-pass-null-in-a-query-string" tabindex="-1">How do I pass NULL in a query string? <a class="header-anchor" href="#how-do-i-pass-null-in-a-query-string" aria-label="Permalink to &quot;How do I pass NULL in a query string?&quot;">​</a></h3><p>By default an empty value (<code>?p=</code>) is an <strong>empty string</strong>, not NULL (<code>QueryStringNullHandling: &quot;Ignore&quot;</code>). Change it per endpoint with <a href="/annotations/query-string-null-handling.html"><code>@query_string_null_handling</code></a> — <code>empty_string</code> makes <code>?p=</code> mean NULL, <code>null_literal</code> makes <code>?p=null</code> mean NULL — or set the global default. For NULLs in <em>text responses</em>, <a href="/annotations/response-null-handling.html"><code>@response_null</code></a> chooses between empty string (default), the literal <code>null</code>, or <code>204 No Content</code>.</p><h3 id="how-do-i-read-http-request-headers-in-my-sql" tabindex="-1">How do I read HTTP request headers in my SQL? <a class="header-anchor" href="#how-do-i-read-http-request-headers-in-my-sql" aria-label="Permalink to &quot;How do I read HTTP request headers in my SQL?&quot;">​</a></h3><p>Add a <code>json</code> or <code>text</code> parameter named <code>_headers</code> with a <code>null</code> default — the default <code>RequestHeadersMode: &quot;Parameter&quot;</code> fills it with all request headers as JSON. The <code>Context</code> mode makes headers readable anywhere via <code>current_setting(&#39;request.headers&#39;, true)</code> instead. Per endpoint: <a href="/annotations/request-headers-mode.html"><code>@request_headers_mode</code></a>.</p><h3 id="how-do-i-receive-a-raw-request-body-webhooks" tabindex="-1">How do I receive a raw request body (webhooks)? <a class="header-anchor" href="#how-do-i-receive-a-raw-request-body-webhooks" aria-label="Permalink to &quot;How do I receive a raw request body (webhooks)?&quot;">​</a></h3><p>Use <a href="/annotations/body-parameter-name.html"><code>@body_parameter_name</code></a> — the entire raw body (text, JSON, or <code>bytea</code>) is routed into that one parameter, and any other parameters automatically move to the query string.</p><h3 id="can-i-validate-parameters-before-they-reach-the-database" tabindex="-1">Can I validate parameters before they reach the database? <a class="header-anchor" href="#can-i-validate-parameters-before-they-reach-the-database" aria-label="Permalink to &quot;Can I validate parameters before they reach the database?&quot;">​</a></h3><p>Yes — <code>@validate &lt;param&gt; using &lt;rule1&gt;, &lt;rule2&gt;</code> runs immediately after parsing, before any database connection is opened. Built-in rules: <code>not_null</code>, <code>not_empty</code>, <code>required</code>, <code>email</code>; custom <code>Regex</code>/<code>MinLength</code>/<code>MaxLength</code> rules with their own status codes and messages are defined in <code>ValidationOptions</code>. See <a href="/config/validation.html">Validation</a> and <a href="/annotations/validate.html"><code>@validate</code></a>.</p><h3 id="error-could-not-determine-data-type-of-parameter" tabindex="-1">Error: &quot;could not determine data type of parameter&quot; <a class="header-anchor" href="#error-could-not-determine-data-type-of-parameter" aria-label="Permalink to &quot;Error: &quot;could not determine data type of parameter&quot;&quot;">​</a></h3><p>PostgreSQL couldn&#39;t infer the parameter&#39;s type from context (classic case: <code>select set_config(&#39;key&#39;, :value, true)</code>). Give it a type hint: <code>-- @param :value text</code> (or <code>-- @param $1 value text</code> positionally), or add an inline cast in the SQL (<code>:value::text</code>).</p><hr><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><h3 id="what-authentication-methods-are-supported" tabindex="-1">What authentication methods are supported? <a class="header-anchor" href="#what-authentication-methods-are-supported" aria-label="Permalink to &quot;What authentication methods are supported?&quot;">​</a></h3><p>Cookie-based auth, JWT Bearer tokens, Microsoft Bearer tokens, HTTP Basic Auth, Passkeys/WebAuthn (FIDO2), and external OAuth providers (Google, GitHub, LinkedIn, Microsoft, Facebook). All can be enabled simultaneously. See <a href="/config/auth.html">Authentication config</a>.</p><h3 id="how-do-i-set-up-jwt-authentication" tabindex="-1">How do I set up JWT authentication? <a class="header-anchor" href="#how-do-i-set-up-jwt-authentication" aria-label="Permalink to &quot;How do I set up JWT authentication?&quot;">​</a></h3><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Auth</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">JwtAuth</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> true</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">JwtSecret</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;your-secret-key-at-least-32-characters-long&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">JwtExpire</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;60 minutes&quot;</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></details><p>See the <a href="/blog/multiple-auth-schemes-rbac-external-providers.html">Multiple Auth Schemes blog post</a> for a complete walkthrough including login endpoints and RBAC.</p><h3 id="how-do-i-create-a-login-endpoint" tabindex="-1">How do I create a login endpoint? <a class="header-anchor" href="#how-do-i-create-a-login-endpoint" aria-label="Permalink to &quot;How do I create a login endpoint?&quot;">​</a></h3><p>Annotate a routine or SQL file with <a href="/annotations/login.html"><code>@login</code></a> (usually together with <code>@allow_anonymous</code>). It returns <strong>one row</strong>: a few special columns (<code>status</code>, <code>scheme</code>, <code>body</code>, <code>hash</code>) control the response, and <strong>every other column becomes a claim</strong> on the signed-in user — no row returned means 401. Verify the password yourself in SQL, or return a <code>hash</code> column and let the built-in PBKDF2 hasher verify it. Full walkthrough in the <a href="/guide/authentication.html">Authentication guide</a>.</p><h3 id="how-do-i-log-users-out" tabindex="-1">How do I log users out? <a class="header-anchor" href="#how-do-i-log-users-out" aria-label="Permalink to &quot;How do I log users out?&quot;">​</a></h3><p>Annotate an endpoint with <a href="/annotations/logout.html"><code>@logout</code></a>. A <code>void</code> routine signs the caller out of all schemes; returned values are treated as scheme names to sign out of selectively.</p><h3 id="how-do-i-hash-passwords-when-creating-users" tabindex="-1">How do I hash passwords when creating users? <a class="header-anchor" href="#how-do-i-hash-passwords-when-creating-users" aria-label="Permalink to &quot;How do I hash passwords when creating users?&quot;">​</a></h3><p>Use <code>-- @param hashed_password is hash of password</code> — the target parameter receives a PBKDF2-SHA256 hash of the source parameter before the routine runs, compatible with <code>@login</code>&#39;s built-in verification. The CLI can hash too: <code>npgsqlrest --hash &lt;password&gt;</code>. See <a href="/annotations/parameter-hash.html">parameter hashing</a>.</p><h3 id="how-do-i-add-social-login-google-github-microsoft" tabindex="-1">How do I add social login (Google, GitHub, Microsoft…)? <a class="header-anchor" href="#how-do-i-add-social-login-google-github-microsoft" aria-label="Permalink to &quot;How do I add social login (Google, GitHub, Microsoft…)?&quot;">​</a></h3><p>Enable <code>Auth.External</code> and add a provider block with <code>ClientId</code> and <code>ClientSecret</code> — Google, GitHub, LinkedIn, Microsoft, and Facebook are pre-configured; custom providers just set their URLs. After the OAuth flow, NpgsqlRest calls your configured <code>LoginCommand</code> function with the provider data, and its result follows the same columns-to-claims conventions as <a href="/annotations/login.html"><code>@login</code></a>. See <a href="/config/external-auth.html">External Auth</a>.</p><h3 id="my-spa-on-a-different-domain-loses-the-session-cookie-—-why" tabindex="-1">My SPA on a different domain loses the session cookie — why? <a class="header-anchor" href="#my-spa-on-a-different-domain-loses-the-session-cookie-—-why" aria-label="Permalink to &quot;My SPA on a different domain loses the session cookie — why?&quot;">​</a></h3><p>Browsers drop cookies on cross-site requests unless the cookie is explicitly marked for it: set <code>Auth.CookieSameSite: &quot;None&quot;</code> together with <code>Auth.CookieSecure: &quot;Always&quot;</code> (and typically <code>CookieDomain</code>), and enable CORS with <code>AllowCredentials: true</code> and explicit origins. See <a href="/config/auth.html">Auth config</a> and <a href="/config/cors.html">CORS</a>.</p><hr><h2 id="real-time-uploads-integrations" tabindex="-1">Real-time, Uploads &amp; Integrations <a class="header-anchor" href="#real-time-uploads-integrations" aria-label="Permalink to &quot;Real-time, Uploads &amp; Integrations&quot;">​</a></h2><h3 id="how-do-i-push-real-time-events-to-the-browser" tabindex="-1">How do I push real-time events to the browser? <a class="header-anchor" href="#how-do-i-push-real-time-events-to-the-browser" aria-label="Permalink to &quot;How do I push real-time events to the browser?&quot;">​</a></h3><p>Server-Sent Events: annotate a routine with <a href="/annotations/sse.html"><code>@sse</code></a> and every <code>raise info</code> it makes is broadcast to subscribers connected to the endpoint&#39;s stream URL (<code>&lt;path&gt;/info</code> by default). Control who receives events with <a href="/annotations/sse-events-scope.html"><code>@sse_scope</code></a> — <code>all</code>, <code>authorize [roles]</code>, or <code>matching</code>. See the <a href="/guide/sse.html">SSE guide</a> and the <a href="/blog/real-time-chat-postgresql-sse-npgsqlrest.html">real-time chat blog post</a>.</p><h3 id="how-do-i-accept-file-uploads" tabindex="-1">How do I accept file uploads? <a class="header-anchor" href="#how-do-i-accept-file-uploads" aria-label="Permalink to &quot;How do I accept file uploads?&quot;">​</a></h3><p>Enable <code>UploadOptions</code> and annotate the endpoint with <a href="/annotations/upload.html"><code>@upload</code></a>. Four handlers: <code>large_object</code> (default — PostgreSQL Large Objects), <code>file_system</code>, and <code>csv</code>/<code>excel</code>, which parse the file and run a SQL command per row (bulk ingestion without client code). Upload metadata arrives in a <code>json</code> parameter, and everything is transactional — an exception rolls back the rows <em>and</em> discards the file. See <a href="/config/uploads.html">Uploads</a> and the <a href="/blog/secure-image-uploads-postgresql-typescript.html">secure image uploads post</a>.</p><h3 id="can-my-sql-call-an-external-http-api" tabindex="-1">Can my SQL call an external HTTP API? <a class="header-anchor" href="#can-my-sql-call-an-external-http-api" aria-label="Permalink to &quot;Can my SQL call an external HTTP API?&quot;">​</a></h3><p>Yes — <strong>HTTP Custom Types</strong>: create a composite type whose comment describes a request (<code>GET https://api.example.com/{id}</code>, headers, body), take it as a function parameter, and NpgsqlRest executes the call and fills the type&#39;s fields (<code>body</code>, <code>status_code</code>, <code>success</code>, …) before your function runs. Requires <code>HttpClientOptions.Enabled: true</code>; supports timeouts, retries, and GET response caching. See <a href="/guide/http-types.html">HTTP Custom Types</a>.</p><h3 id="can-npgsqlrest-forward-requests-to-another-service-reverse-proxy" tabindex="-1">Can NpgsqlRest forward requests to another service (reverse proxy)? <a class="header-anchor" href="#can-npgsqlrest-forward-requests-to-another-service-reverse-proxy" aria-label="Permalink to &quot;Can NpgsqlRest forward requests to another service (reverse proxy)?&quot;">​</a></h3><p>Yes — <a href="/annotations/proxy.html"><code>@proxy</code></a> forwards the request to an upstream URL and streams the response back without touching the database; declare <code>_proxy_*</code> parameters to transform the upstream response in SQL instead. <a href="/annotations/proxy-out.html"><code>@proxy_out</code></a> is the reverse: run your routine first, then send its result upstream (PDF rendering, ML inference, email). Requires <code>ProxyOptions.Enabled</code>. See the <a href="/guide/proxy.html">Proxy guide</a>.</p><h3 id="how-do-i-expose-functions-as-ai-tools-mcp" tabindex="-1">How do I expose functions as AI tools (MCP)? <a class="header-anchor" href="#how-do-i-expose-functions-as-ai-tools-mcp" aria-label="Permalink to &quot;How do I expose functions as AI tools (MCP)?&quot;">​</a></h3><p>Enable <code>McpOptions</code> and annotate routines with <a href="/annotations/mcp.html"><code>@mcp</code></a> — only annotated routines are exposed, on a single <code>/mcp</code> endpoint (streamable HTTP). <code>@mcp</code> without an HTTP annotation makes a tool-only routine with no REST route, and <code>@authorize</code> roles are enforced on tool calls. Since 3.20.0, <a href="/config/mcp.html#function-calling-schemas-and-llms-txt-toolschemas"><code>McpOptions.ToolSchemas</code></a> can also project the same tool catalog into OpenAI and Anthropic function-calling <code>tools</code> documents and an llms.txt — generated and served even when the <code>/mcp</code> endpoint is disabled. See <a href="/config/mcp.html">MCP</a> and the <a href="/blog/mcp-server-postgresql-ai-tools-npgsqlrest.html">MCP server blog post</a>.</p><h3 id="can-it-generate-a-client-—-typescript-dart-http-files-openapi" tabindex="-1">Can it generate a client — TypeScript, Dart, <code>.http</code> files, OpenAPI? <a class="header-anchor" href="#can-it-generate-a-client-—-typescript-dart-http-files-openapi" aria-label="Permalink to &quot;Can it generate a client — TypeScript, Dart, \`.http\` files, OpenAPI?&quot;">​</a></h3><p>All of them, regenerated on every <a href="/config/watch.html">watch</a> cycle: <code>ClientCodeGen</code> emits typed TypeScript fetch modules with interfaces (and, since 3.20.0, optional <a href="/config/react-query.html">TanStack Query hooks</a> via <code>ReactQuery</code>), <code>DartClientCodeGen</code> (3.20.0) emits <a href="/config/dart-codegen.html">Dart modules for Flutter</a>, <code>HttpFileOptions</code> writes ready-to-run <code>.http</code> files, and <code>OpenApiOptions</code> serves <code>openapi.json</code> (hide individual endpoints with <a href="/annotations/openapi.html"><code>@openapi hide</code></a>). See <a href="/config/codegen.html">Code Generation</a>, <a href="/config/dart-codegen.html">Dart Code Generation</a>, <a href="/config/http-files.html">HTTP Files</a>, and <a href="/config/openapi.html">OpenAPI</a>.</p><hr><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><h3 id="how-do-i-test-my-endpoints" tabindex="-1">How do I test my endpoints? <a class="header-anchor" href="#how-do-i-test-my-endpoints" aria-label="Permalink to &quot;How do I test my endpoints?&quot;">​</a></h3><p>With the built-in <a href="/guide/testing.html">SQL test runner</a> (since 3.19.0): write tests as plain <code>.sql</code> files and run <code>npgsqlrest ./config.json --test</code>. A test inserts fixtures, invokes a real endpoint <strong>in-process</strong> (full pipeline: routing, auth, parameter binding, serialization), asserts on the captured response with ordinary SQL, and rolls back — endpoints see the test&#39;s uncommitted data because they run on the test&#39;s own connection and transaction.</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">begin</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">insert into</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users (email) </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">values</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> (</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;x@example.com&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">/*</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">GET /api/get-users</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;"># @claim user_id=1</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">*/</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">select</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> status</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;"> =</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> 200</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">, </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;authenticated caller gets 200&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> from</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> _response;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">rollback</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div></details><h3 id="can-tests-run-against-a-temporary-database-instead-of-my-real-one" tabindex="-1">Can tests run against a temporary database instead of my real one? <a class="header-anchor" href="#can-tests-run-against-a-temporary-database-instead-of-my-real-one" aria-label="Permalink to &quot;Can tests run against a temporary database instead of my real one?&quot;">​</a></h3><p>Yes — that&#39;s the recommended CI setup. <code>Setup</code> steps create (and <code>Teardown</code> drops) a uniquely named database (<code>app_test_{rnd5}</code>), migrations run as a step, and <code>TestRunner.ConnectionName</code> points the whole run at it. Template databases give per-test clones for perfect isolation. See the <a href="/guide/testing.html#scenario-dedicated-test-database-per-run">scenario catalog in the Testing Guide</a>.</p><h3 id="my-test-fixtures-need-half-the-database-inserted-first-—-is-there-a-better-way" tabindex="-1">My test fixtures need half the database inserted first — is there a better way? <a class="header-anchor" href="#my-test-fixtures-need-half-the-database-inserted-first-—-is-there-a-better-way" aria-label="Permalink to &quot;My test fixtures need half the database inserted first — is there a better way?&quot;">​</a></h3><p>Yes, and it&#39;s pure PostgreSQL: declare your foreign keys <strong><code>deferrable</code></strong>, then start the test with <code>set constraints all deferred;</code>. Deferred constraints are checked at <code>COMMIT</code> — and a test that ends in <code>rollback</code> never commits, so you can insert <strong>only the rows the test is about</strong>, in any order, referencing rows that don&#39;t exist. No fixture factories, no dependency-ordered setup. See <a href="/guide/testing.html#fixtures-without-inserting-the-whole-database-deferrable-constraints">the technique in the Testing Guide</a>.</p><h3 id="is-there-a-watch-mode" tabindex="-1">Is there a watch mode? <a class="header-anchor" href="#is-there-a-watch-mode" aria-label="Permalink to &quot;Is there a watch mode?&quot;">​</a></h3><p>Two, with one flag. <code>npgsqlrest ... --test --watch</code> re-runs <strong>tests</strong> on changes — a changed test re-runs alone in milliseconds; a changed <em>endpoint</em> file or <em>database routine</em> rebuilds the endpoints in-process and re-runs everything, reporting exactly which endpoints appeared or dropped; Ctrl+C still tears the test database down. <code>npgsqlrest ... --watch</code> (without <code>--test</code>) watches the <strong>running server</strong> — it restarts on SQL file, configuration, and database routine changes, regenerating code (TypeScript client, HTTP files) on every cycle, so <code>create or replace</code> a function in psql and the endpoint is live seconds later. See <a href="/config/watch.html">Watch Mode configuration</a>.</p><hr><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><h3 id="how-fast-is-it" tabindex="-1">How fast is it? <a class="header-anchor" href="#how-fast-is-it" aria-label="Permalink to &quot;How fast is it?&quot;">​</a></h3><p>Independent-methodology benchmarks measure thousands of requests per second on a single host — see the <a href="/blog/benchmarks-2026-07/">July 2026 benchmark series</a> for detailed comparisons against PostgREST, Go, Rust, Spring Boot, FastAPI, and others under equalized conditions, including the methodology, per-framework analysis, and the full dataset. The executables are AOT-compiled native binaries; there is no JIT warmup and no reflection at runtime.</p><h3 id="how-do-i-enable-caching" tabindex="-1">How do I enable caching? <a class="header-anchor" href="#how-do-i-enable-caching" aria-label="Permalink to &quot;How do I enable caching?&quot;">​</a></h3><p>Annotate with <a href="/annotations/cached.html"><code>@cached</code></a> (+ <code>@cache_expires_in 5 minutes</code>). The backend (Memory, Redis, or HybridCache) is configured in <a href="/config/cache-options.html">Cache Options</a>; per-user and per-parameter cache keys are supported. For conditional or tiered rules (&quot;skip caching for admins&quot;, &quot;shorter TTL for open-ended queries&quot;), bundle settings into named profiles and select them with <a href="/annotations/cache-profile.html"><code>@cache_profile</code></a>. <strong>Note:</strong> <code>@cached</code> only works for endpoints returning a <strong>single scalar value</strong> — set-returning or multi-column results log a warning and aren&#39;t cached.</p><h3 id="how-do-i-enable-response-compression" tabindex="-1">How do I enable response compression? <a class="header-anchor" href="#how-do-i-enable-response-compression" aria-label="Permalink to &quot;How do I enable response compression?&quot;">​</a></h3><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">ResponseCompression</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Enabled</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> true</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>See <a href="/config/response-compression.html">Response Compression</a>.</p><h3 id="how-do-i-set-up-rate-limiting" tabindex="-1">How do I set up rate limiting? <a class="header-anchor" href="#how-do-i-set-up-rate-limiting" aria-label="Permalink to &quot;How do I set up rate limiting?&quot;">​</a></h3><p>Define policies in <a href="/config/rate-limiter.html">Rate Limiter config</a> and apply them per endpoint with <a href="/annotations/rate-limiter-policy.html"><code>@rate_limiter_policy</code></a>.</p><h3 id="should-i-use-the-aot-or-the-jit-docker-image" tabindex="-1">Should I use the AOT or the JIT Docker image? <a class="header-anchor" href="#should-i-use-the-aot-or-the-jit-docker-image" aria-label="Permalink to &quot;Should I use the AOT or the JIT Docker image?&quot;">​</a></h3><p>The default AOT image (~60 MB compressed) starts instantly — best for development, CLI use, and scale-to-zero deployments. The JIT variant (<code>vbilopav/npgsqlrest:latest-jit</code>) is 50–100% faster under sustained high concurrency, at the cost of slower cold start and a ~110 MB compressed image — recommended for sustained high-throughput production workloads. See <a href="/guide/installation.html#jit-image">Installation — JIT Image</a>.</p><h3 id="how-do-i-stream-very-large-result-sets" tabindex="-1">How do I stream very large result sets? <a class="header-anchor" href="#how-do-i-stream-very-large-result-sets" aria-label="Permalink to &quot;How do I stream very large result sets?&quot;">​</a></h3><p>Responses are flushed every 25 rows by default. <a href="/annotations/buffer-rows.html"><code>@buffer_rows 0</code></a> writes each row as it arrives (constant memory, immediate first byte); higher values trade memory for throughput.</p><hr><h2 id="deployment-production" tabindex="-1">Deployment &amp; Production <a class="header-anchor" href="#deployment-production" aria-label="Permalink to &quot;Deployment &amp; Production&quot;">​</a></h2><h3 id="my-browser-app-gets-cors-errors-—-how-do-i-allow-my-frontend-origin" tabindex="-1">My browser app gets CORS errors — how do I allow my frontend origin? <a class="header-anchor" href="#my-browser-app-gets-cors-errors-—-how-do-i-allow-my-frontend-origin" aria-label="Permalink to &quot;My browser app gets CORS errors — how do I allow my frontend origin?&quot;">​</a></h3><p>Enable the <code>Cors</code> section and list origins explicitly. <code>AllowCredentials</code> defaults to <code>false</code> — cookie-based auth needs it <code>true</code>, together with explicit <code>AllowedOrigins</code> (browsers reject <code>*</code> combined with credentials):</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Cors</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Enabled</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> true</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">AllowedOrigins</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> [</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&quot;https://app.example.com&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">],</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">AllowCredentials</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> true</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></details><p>See <a href="/config/cors.html">CORS</a>.</p><h3 id="behind-nginx-cloudflare-the-client-ip-is-wrong" tabindex="-1">Behind nginx / Cloudflare the client IP is wrong <a class="header-anchor" href="#behind-nginx-cloudflare-the-client-ip-is-wrong" aria-label="Permalink to &quot;Behind nginx / Cloudflare the client IP is wrong&quot;">​</a></h3><p>Enable the <code>ForwardedHeaders</code> section so <code>X-Forwarded-For</code>/<code>-Proto</code> are honored — this affects logs, rate limiting, and the <code>request.ip_address</code> context value. Set <code>ForwardLimit</code> to your proxy-chain depth and restrict trust with <code>KnownProxies</code>/<code>KnownNetworks</code>; with both lists empty, the headers are accepted from any source. See <a href="/config/forwarded-headers.html">Forwarded Headers</a>.</p><h3 id="can-i-run-behind-pgbouncer-rds-proxy-supabase-pooler-in-transaction-mode" tabindex="-1">Can I run behind PgBouncer / RDS Proxy / Supabase Pooler in transaction mode? <a class="header-anchor" href="#can-i-run-behind-pgbouncer-rds-proxy-supabase-pooler-in-transaction-mode" aria-label="Permalink to &quot;Can I run behind PgBouncer / RDS Proxy / Supabase Pooler in transaction mode?&quot;">​</a></h3><p>Yes — set <code>NpgsqlRest.WrapInTransaction: true</code>. It wraps every request in <code>BEGIN</code>…<code>COMMIT</code>, which keeps <code>set_config</code> state (claims, headers, user context) local to the request instead of leaking across pooled backends. Required for any pooler in transaction mode. See <a href="/config/npgsqlrest.html">NpgsqlRest Options</a>.</p><h3 id="is-there-a-health-endpoint-for-kubernetes-or-load-balancers" tabindex="-1">Is there a health endpoint for Kubernetes or load balancers? <a class="header-anchor" href="#is-there-a-health-endpoint-for-kubernetes-or-load-balancers" aria-label="Permalink to &quot;Is there a health endpoint for Kubernetes or load balancers?&quot;">​</a></h3><p>Enable <code>HealthChecks</code>: <code>/health</code> (overall), <code>/health/ready</code> (includes a PostgreSQL connectivity check), and <code>/health/live</code> (no database check — so a database outage doesn&#39;t restart your pods). See <a href="/config/health-checks.html">Health Checks</a>.</p><h3 id="can-i-route-endpoints-to-a-read-replica-or-a-second-database" tabindex="-1">Can I route endpoints to a read replica or a second database? <a class="header-anchor" href="#can-i-route-endpoints-to-a-read-replica-or-a-second-database" aria-label="Permalink to &quot;Can I route endpoints to a read replica or a second database?&quot;">​</a></h3><p>Yes — two mechanisms, depending on whether the databases have the same routines. For <strong>identical</strong> databases (read replicas, shards): define multiple named entries in <code>ConnectionStrings</code>, set <code>NpgsqlRest.UseMultipleConnections: true</code>, and pick per endpoint with <a href="/annotations/connection.html"><code>@connection &lt;name&gt;</code></a> — metadata is still read once, and the target is assumed to have the same routine. For databases hosting <strong>different</strong> routines (OLTP + OLAP/DW): list them in <code>NpgsqlRest.RoutineOptions.ReadMetadataFromConnections</code> (3.21.0+) — routine metadata is read from each listed connection and endpoints execute where they were discovered, no duplication on the main database needed. Without <code>NpgsqlRest.ConnectionName</code>, the first entry is the main connection. Comma-separated hosts in one connection string become a multi-host data source with failover and load balancing. See the <a href="/guide/connections.html">Connection Management guide</a> for the full scenario walkthrough and <a href="/config/connection.html">Connection Settings</a> for the reference.</p><h3 id="does-it-retry-transient-errors" tabindex="-1">Does it retry transient errors? <a class="header-anchor" href="#does-it-retry-transient-errors" aria-label="Permalink to &quot;Does it retry transient errors?&quot;">​</a></h3><p>Two layers, both on by default. Connection failures (startup included) retry on a 1, 3, 6, 12-second sequence, so the server survives the database starting after it does. Command execution retries transient SQLSTATEs — serialization failures (<code>40001</code>), deadlocks (<code>40P01</code>), dropped connections — on a 0, 1, 2, 5, 10-second sequence; define named strategies and assign them per endpoint with <a href="/annotations/retry-strategy.html"><code>@retry_strategy</code></a>. <strong>Important:</strong> mutations (INSERT/UPDATE/DELETE) can be retried and re-executed on a deadlock or serialization failure — they should be idempotent or accept duplicate attempts. See <a href="/config/command-retry.html">Command Retry</a> and <a href="/config/connection.html">Connection Settings</a>.</p><hr><h2 id="debugging-logging" tabindex="-1">Debugging &amp; Logging <a class="header-anchor" href="#debugging-logging" aria-label="Permalink to &quot;Debugging &amp; Logging&quot;">​</a></h2><h3 id="how-do-i-see-which-endpoints-are-created-and-what-options-they-have" tabindex="-1">How do I see which endpoints are created and what options they have? <a class="header-anchor" href="#how-do-i-see-which-endpoints-are-created-and-what-options-they-have" aria-label="Permalink to &quot;How do I see which endpoints are created and what options they have?&quot;">​</a></h3><p>Set the <code>NpgsqlRest</code> log level to <code>Debug</code> — every endpoint logs as it is created, including which annotations were applied:</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Log</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">MinimalLevels</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">NpgsqlRest</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Debug&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>Or list them without starting the server: <code>npgsqlrest --endpoints</code>.</p><h3 id="how-do-i-log-the-sql-each-endpoint-executes-at-runtime" tabindex="-1">How do I log the SQL each endpoint executes at runtime? <a class="header-anchor" href="#how-do-i-log-the-sql-each-endpoint-executes-at-runtime" aria-label="Permalink to &quot;How do I log the SQL each endpoint executes at runtime?&quot;">​</a></h3><p>Two settings: <code>&quot;LogCommands&quot;: true</code> in the <code>NpgsqlRest</code> section opts in, and the <code>NpgsqlRest</code> channel must be at <code>Verbose</code> (commands log at trace level):</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">NpgsqlRest</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">LogCommands</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> true</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> },</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Log</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">MinimalLevels</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">NpgsqlRest</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Verbose&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><p>Add <code>&quot;LogCommandParameters&quot;: true</code> to include parameter values (mind the sensitive-data implications in production — <a href="/annotations/security-sensitive.html"><code>@security_sensitive</code></a> obfuscates a specific endpoint). See the <a href="/guide/logging.html">Logging Guide</a> for the full picture.</p><h3 id="how-do-i-see-the-metadata-queries-npgsqlrest-runs-at-startup" tabindex="-1">How do I see the metadata queries NpgsqlRest runs at startup? <a class="header-anchor" href="#how-do-i-see-the-metadata-queries-npgsqlrest-runs-at-startup" aria-label="Permalink to &quot;How do I see the metadata queries NpgsqlRest runs at startup?&quot;">​</a></h3><p>Set the <code>NpgsqlRest</code> log level to <code>Verbose</code> — includes everything from <code>Debug</code> plus the raw <code>pg_catalog</code> discovery queries and the SQL-file describe phase. Useful when a function or file isn&#39;t being discovered and you need to see the underlying query and its filters.</p><h3 id="how-do-i-completely-silence-a-logger" tabindex="-1">How do I completely silence a logger? <a class="header-anchor" href="#how-do-i-completely-silence-a-logger" aria-label="Permalink to &quot;How do I completely silence a logger?&quot;">​</a></h3><p>Since 3.19.0 any <code>Log:MinimalLevels</code> entry accepts <code>&quot;Off&quot;</code> (aliases <code>&quot;None&quot;</code>, <code>&quot;Silent&quot;</code>):</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Log</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">MinimalLevels</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">NpgsqlRest</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Off&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">NpgsqlRestClient</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;Off&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>Each named logger is independent — handy for muting the application channels while watching the test runner&#39;s <code>NpgsqlRestTest</code> channel.</p><h3 id="why-do-my-raise-messages-appear-in-the-server-log" tabindex="-1">Why do my RAISE messages appear in the server log? <a class="header-anchor" href="#why-do-my-raise-messages-appear-in-the-server-log" aria-label="Permalink to &quot;Why do my RAISE messages appear in the server log?&quot;">​</a></h3><p><code>LogConnectionNoticeEvents</code> is on by default — <code>raise info/notice/warning</code> from executing routines is written to the application log (the same mechanism that powers <a href="/guide/sse.html">SSE</a>). Set it to <code>false</code> in the <code>NpgsqlRest</code> section to silence them, or tune the format with <code>LogConnectionNoticeEventsMode</code>. See the <a href="/guide/logging.html">Logging Guide</a>.</p><h3 id="how-do-i-validate-the-configuration-without-starting-the-server" tabindex="-1">How do I validate the configuration without starting the server? <a class="header-anchor" href="#how-do-i-validate-the-configuration-without-starting-the-server" aria-label="Permalink to &quot;How do I validate the configuration without starting the server?&quot;">​</a></h3><p><code>npgsqlrest --validate</code> checks configuration keys <em>and</em> database connectivity, exiting 0 on success and 1 on failure — CI-friendly. Related: <code>--config</code> prints the fully resolved annotated configuration, <code>--annotations</code> lists every supported comment annotation as JSON, and <code>--endpoints</code> lists the endpoints that would be created. See <a href="/guide/installation.html">Installation — CLI</a>.</p><h3 id="can-i-use-the-cli-to-generate-password-hashes" tabindex="-1">Can I use the CLI to generate password hashes? <a class="header-anchor" href="#can-i-use-the-cli-to-generate-password-hashes" aria-label="Permalink to &quot;Can I use the CLI to generate password hashes?&quot;">​</a></h3><p>Yes — <code>npgsqlrest --hash &lt;password&gt;</code> generates a PBKDF2-SHA256 hash compatible with <a href="/annotations/login.html"><code>@login</code></a> and password parameters. For HTTP Basic auth, <code>npgsqlrest --basic_auth &lt;user&gt; &lt;password&gt;</code> outputs the header value to add to a request.</p><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="every-endpoint-returns-401-unauthorized" tabindex="-1">Every endpoint returns 401 Unauthorized <a class="header-anchor" href="#every-endpoint-returns-401-unauthorized" aria-label="Permalink to &quot;Every endpoint returns 401 Unauthorized&quot;">​</a></h3><p>That is the default posture, not a bug: the standalone client ships with <code>RequiresAuthorization: true</code>, so endpoints require an authenticated user unless annotated otherwise. Add <a href="/annotations/allow-anonymous.html"><code>@allow_anonymous</code></a> to public endpoints, or set <code>NpgsqlRest.RequiresAuthorization</code> to <code>false</code> and protect endpoints individually with <a href="/annotations/authorize.html"><code>@authorize</code></a>.</p><h3 id="startup-warning-unknown-configuration-key" tabindex="-1">Startup warning: &quot;Unknown configuration key&quot; <a class="header-anchor" href="#startup-warning-unknown-configuration-key" aria-label="Permalink to &quot;Startup warning: &quot;Unknown configuration key&quot;&quot;">​</a></h3><p>Almost always a typo in <code>appsettings.json</code> — keys are validated at startup. Run <code>npgsqlrest --config</code> to print the complete annotated configuration, or use the published JSON schema for editor autocompletion.</p><h3 id="error-permission-denied-for-schema" tabindex="-1">Error: &quot;permission denied for schema&quot; <a class="header-anchor" href="#error-permission-denied-for-schema" aria-label="Permalink to &quot;Error: &quot;permission denied for schema&quot;&quot;">​</a></h3><p>The database user lacks <code>USAGE</code> on the schema:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">grant</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> usage </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">on</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> schema</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> my_schema </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">to</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> my_user;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">grant</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> execute</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> on</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> all functions </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">in</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> schema</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> my_schema </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">to</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> my_user;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><p>This is also a feature: run the server as a least-privilege role and endpoints can only do what that role can do.</p><h3 id="timeout-errors-504-gateway-timeout" tabindex="-1">Timeout errors (504 Gateway Timeout) <a class="header-anchor" href="#timeout-errors-504-gateway-timeout" aria-label="Permalink to &quot;Timeout errors (504 Gateway Timeout)&quot;">​</a></h3><p>Adjust the command timeout per endpoint with <a href="/annotations/command-timeout.html"><code>@command_timeout 2 minutes</code></a>, or globally in configuration.</p><h3 id="my-post-body-seems-ignored-—-the-endpoint-returns-404" tabindex="-1">My POST body seems ignored — the endpoint returns 404 <a class="header-anchor" href="#my-post-body-seems-ignored-—-the-endpoint-returns-404" aria-label="Permalink to &quot;My POST body seems ignored — the endpoint returns 404&quot;">​</a></h3><p>Request bodies are read as <strong>JSON regardless of the <code>Content-Type</code> header</strong> — there is no content-type validation, and form-encoded/form-multipart bodies are never parsed (multipart files are only for <a href="/annotations/upload.html"><code>@upload</code></a> endpoints). A malformed JSON body logs a warning (<code>Could not parse JSON body ...</code>) and the request proceeds with <strong>no parameters</strong>, which then fails endpoint matching with a 404. Always send valid JSON, and the <code>Content-Type</code> header can be anything or omitted.</p><h3 id="_413-payload-too-large" tabindex="-1">413 Payload Too Large <a class="header-anchor" href="#_413-payload-too-large" aria-label="Permalink to &quot;413 Payload Too Large&quot;">​</a></h3><p>Kestrel caps request bodies at 30,000,000 bytes (~28.6 MB) by default — large uploads hit this before any NpgsqlRest setting. Raise <code>Kestrel.Limits.MaxRequestBodySize</code> in <a href="/config/server.html">Server settings</a>.</p><h3 id="timestamps-shifted-after-upgrading-to-3-16" tabindex="-1">Timestamps shifted after upgrading to 3.16+ <a class="header-anchor" href="#timestamps-shifted-after-upgrading-to-3-16" aria-label="Permalink to &quot;Timestamps shifted after upgrading to 3.16+&quot;">​</a></h3><p>Since 3.16.0, timestamps in JSON are treated as <strong>UTC</strong> by default (naive ISO strings assumed UTC, offset strings converted), so stored values no longer depend on the host&#39;s timezone. If you relied on the old host-local parsing, <code>NpgsqlRest.JsonTimestampsAreUtc: false</code> restores it — but treat that as a compatibility escape hatch, not a setting for new projects.</p><h3 id="encrypted-data-is-unreadable-after-restart" tabindex="-1">Encrypted data is unreadable after restart <a class="header-anchor" href="#encrypted-data-is-unreadable-after-restart" aria-label="Permalink to &quot;Encrypted data is unreadable after restart&quot;">​</a></h3><p>Data Protection keys default to in-memory on Linux — configure persistent storage:</p><details class="code-collapsible" open><summary>json</summary><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">DataProtection</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">Storage</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;FileSystem&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">FileSystemPath</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;/var/lib/npgsqlrest/keys&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>See <a href="/config/data-protection.html">Data Protection config</a>.</p><h3 id="leftover-abcde-test-databases" tabindex="-1">Leftover <code>*_abcde</code> test databases <a class="header-anchor" href="#leftover-abcde-test-databases" aria-label="Permalink to &quot;Leftover \`*_abcde\` test databases&quot;">​</a></h3><p>The test runner drops its <code>{rnd}</code>-named databases on every exit path it can intercept — including Ctrl+C, SIGTERM, and hard startup errors. Leftovers mean a run was killed with SIGKILL (nothing can intercept that) or ran with <code>Keep: true</code>. Drop them manually:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">select</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> format</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">(</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;drop database %I with (force);&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">, datname)</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">from</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> pg_database </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">where</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> datname </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">like</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;app_test_%&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> \\gexec</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details>`,212)]))}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
